<?php use App\Core\Helpers as H;use App\Services\EmailCampaignService;$audience=$campaign['audience']??'waitlist_all';?><section class="panel narrow"><h1>Create promotional campaign</h1><?php foreach($errors as $e):?><div class="notice warning"><?=H::e($e)?></div><?php endforeach;?><?php if($preview):?><div class="email-preview"><h2><?=H::e($campaign['subject']??'')?></h2><p><?=nl2br(H::e($campaign['body']??''))?></p><?php if(!empty($campaign['cta_url'])):?><a href="<?=H::e($campaign['cta_url'])?>"><?=H::e($campaign['cta_label']??'')?></a><?php endif;?><p><small>An unsubscribe link will be added for every recipient.</small></p></div><?php endif;?><form method="post"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><label>Audience<select name="audience"><?php foreach(EmailCampaignService::AUDIENCES as $a):?><option value="<?=$a?>" <?=$audience===$a?'selected':''?>><?=H::e(EmailCampaignService::audienceLabel($a))?></option><?php endforeach;?></select></label><label>Subject<input maxlength="190" name="subject" value="<?=H::e($campaign['subject']??'')?>"></label><label>Body<textarea maxlength="10000" rows="12" name="body"><?=H::e($campaign['body']??'')?></textarea></label><label>CTA label<input maxlength="80" name="cta_label" value="<?=H::e($campaign['cta_label']??'')?>"></label><label>CTA URL<input maxlength="500" name="cta_url" value="<?=H::e($campaign['cta_url']??'')?>" placeholder="/browse"></label><button name="action" value="preview">Preview</button><button name="action" value="save">Save draft</button><button name="action" value="queue">Save and queue</button></form></section>
